mapper.select:
SELECT stock_code, stock_name, trade_time AS trade_date, open, high, low, close, vol, amount, percent, pre_close
FROM t_stock_quote_60
WHERE stock_code IN

    #{code}

  AND trade_time >= #{startTradeDateInclusive}
  AND trade_time < #{endTradeDateExclusive}
ORDER BY stock_code, trade_time
